import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def extract(data):
    result = {}
    for p in data.get('projects', []):
        name = p['path'].split('/')[-1]
        for fw in p.get('frameworks', []):
            for pkg in fw.get('topLevelPackages', []):
                result[(name, pkg['id'])] = pkg['resolvedVersion']
    return result

b, a = extract(baseline), extract(after)
if b == a:
    print('All packages resolve identically. Conversion is version-neutral.')
else:
    for k in sorted(set(list(b.keys()) + list(a.keys()))):
        bv, av = b.get(k, 'MISSING'), a.get(k, 'MISSING')
        if bv != av:
            print(f'CHANGED: {k[0]} {k[1]}: {bv} -> {av}')
"

